int findpar(int node)
{
	return parr[node]==node ? node : parr[node]=findpar(parr[node]);
}
void dfs(int node, int par, int inh, int com)
{
	parent[node][0]=par;
	inherit[node]=inh;
	comp[node]=com;
	height[node]=height[par]+1;
	for(int i=1;i<=20;i++)
	{
		parent[node][i]=parent[parent[node][i-1]][i-1];
	}
	for(int i=0;i<v[node].size();i++)
	{
		if(v[node][i]==par)
			continue;
		if(v2[node][i]==0)
			dfs(v[node][i],node,inh+1,com);
		else
			dfs(v[node][i],node,inh,com+1);
	}
}
int findlca(int u, int v)
{
	if(height[u]>height[v])
		swap(u,v);
	for(int i=20;i>=0;i--)
	{
		if(height[parent[v][i]]>=height[u])
		{
			v=parent[v][i];
		}
	}
	if(u!=v)
	{
		for(int i=20;i>=0;i--)
		{
			if(parent[u][i]!=parent[v][i])
			{
				u=parent[u][i];
				v=parent[v][i];
			}
		}
		u=parent[u][0];
		v=parent[v][0];
	}
	return u;
}
